    fun modPow(base: Long, exp: Long, mod: Long): Long {
        var result = 1L
        var b = base % mod
        var e = exp
        while (e > 0) {
            if (e % 2 == 1L) result = result * b % mod
            e /= 2
            b = b * b % mod
        }
        return result
    }

    var r = 0
    var d = (n - 1).toLong()
    while (d % 2 == 0L) { r++; d /= 2 }

    val witnesses = longArrayOf(2, 3, 5, 7)
    for (a in witnesses) {
        if (a >= n) continue

        var x = modPow(a, d, n.toLong())
        if (x == 1L || x == (n - 1).toLong()) continue

        var found = false
        for (i in 0 until r - 1) {
            x = modPow(x, 2, n.toLong())
            if (x == (n - 1).toLong()) { found = true; break }
        }

        if (!found) return 0
    }

    return 1
}

def miller_rabin(n: int) -> int:
    if n < 2:
        return 0
    if n < 4:
        return 1
    if n % 2 == 0:
        return 0

    # Write n-1 as 2^r * d
    r, d = 0, n - 1
    while d % 2 == 0:
        r += 1
        d //= 2

    # Deterministic witnesses for n < 3,215,031,751
    witnesses = [2, 3, 5, 7]

    for a in witnesses:
        if a >= n:
            continue

        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            continue

        found = False
        for _ in range(r - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                found = True
                break

        if not found:
            return 0

    return 1

fn mod_pow(mut base: i64, mut exp: i64, modulus: i64) -> i64 {
    let mut result = 1i64;
    base %= modulus;
    while exp > 0 {
        if exp % 2 == 1 {
            result = result * base % modulus;
        }
        exp /= 2;
        base = base * base % modulus;
    }
    result
}

